"use strict";(()=>{const isNil=s=>s==null,isPresent=s=>!isNil(s);function createMyWidget(containerId,options){const container=document.getElementById(containerId);if(!container)return;const baseUrl="https://moralis.com";container.innerHTML="";const fullOptions={...options,pageUrl:window.location.href};const cleanedOptions=Object.fromEntries(Object.entries(fullOptions).filter(([,val])=>isPresent(val)).map(([key,val])=>[key,typeof val==="string"?val:JSON.stringify(val)]));const width=options.autoSize?"100%":options.width||"100%";const height=options.autoSize?"100%":options.height||"100%";const wrapper=document.createElement("div");wrapper.style.width=width;wrapper.style.height=height;wrapper.style.display="flex";wrapper.style.flexDirection="column";const queryString=new URLSearchParams(cleanedOptions).toString();const iframe=document.createElement("iframe");iframe.id="my-widget-iframe";iframe.src=`${baseUrl}/widgets/embed/price-chart?${queryString}`;Object.assign(iframe.style,{width:"100%",height:"100%",border:"none",overflow:"hidden"});wrapper.appendChild(iframe);container.appendChild(wrapper)}window.createMyWidget=createMyWidget})();
